  "global": "Edit matplotlib/axes/_base.py::Axes.cla() and matplotlib/figure.py::Figure.clf() to loop over all owned artist containers and assign artist.axes = None / artist.figure = None before clearing the containers.",
  "subtasks": [
    {
      "subtask": "Read Artist.remove() to extract the unset pattern",
      "atomics": [
        "Read lib/matplotlib/artist.py, find 'def remove', note 'self.axes = None' line and any guard conditions",
