      ]
    },
    {
      "subtask": "Read and understand Axes.cla() artist containers",
      "atomics": [
        "Read lib/matplotlib/axes/_base.py from 'def cla' through its end",
        "Collect the exact attribute names reset to empty lists: self.lines, self.patches, self.collections, self.images, self.tables, self.artists, self.texts, self._mouseover_set, and self.legend_ (if set)",
        "Identify the earliest safe insertion point: after saving non-artist state but before 'self.lines = []' et al."
      ]
    },
    {
      "subtask": "Insert artist.axes = None loop in Axes.cla()",
      "atomics": [
        "In lib/matplotlib/axes/_base.py::Axes.cla(), add 'for art in self._get_lines... / self.lines + self.patches + ...: art.axes = None' immediately before the container reset block",
        "Use a helper or inline loop covering: self.lines, self.patches, self.collections, self.images, self.tables, self.artists, self.texts, and (if self.legend_ is not None) self.legend_.legendHandles + self.legend_.texts"
      ]
    },
    {
      "subtask": "Read Figure.clf() and insert artist.figure = None loops",
      "atomics": [
        "Read lib/matplotlib/figure.py::Figure.clf() in full",
        "Add loop 'for ax in self.axes: for art in ax.get_children(): art.axes = None; art.figure = None' before axes are cleared",
        "Add loop over figure-level containers (self.lines, self.patches, self.images, self.texts, self.legends, self.artists if they exist) setting art.figure = None"
      ]
    },
    {
      "subtask": "Add regression tests",
      "atomics": [
        "In lib/matplotlib/tests/test_axes.py add: def test_cla_unsets_axes(): f, a = plt.subplots(); l, = a.plot([1,2]); a.cla(); assert l.axes is None",
        "In lib/matplotlib/tests/test_figure.py add: def test_clf_unsets_figure(): f, a = plt.subplots(); l, = a.plot([1,2]); f.clf(); assert l.figure is None and l.axes is None",
        "Run pytest lib/matplotlib/tests/test_axes.py lib/matplotlib/tests/test_figure.py -x and confirm all pass"
      ]
    }
  ],
  "global_atomics": [
    "Execute the exact repro from the bug report: 'f,a=plt.subplots(); l,=a.plot([1,2]); a.cla(); print(l.axes)' and assert output is None",
    "Execute clf repro: 'f,a=plt.subplots(); l,=a.plot([1,2]); f.clf(); print(l.figure)' and assert output is None"
  ]
}

